var e=[{id:`L2_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`그거 사람들에게 나눠 줘.`,JPN:`それはみんなに配ってくれ。`,ENG:`Hand those out to people.`,TWN:`把那個分給大家吃吧。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`포춘 쿠키를? 공짜로?`,JPN:`フォーチュンクッキーを？　タダで？`,ENG:`The fortune cookies? For free?`,TWN:`幸運餅乾嗎？免費送？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`어찌 됐건 하트 포인트 덕분에 물리친 거잖아. 사은품이라고 해 두지 뭐.`,JPN:`とにかくハートポイントのおかげで倒せたんだ。プレゼントということにしておこう。`,ENG:`Well, we defeated them thanks to the Heart Points. Let's just say it's a souvenir.`,TWN:`因為那些愛心點數才能趕走她的嘛，就當是謝禮吧。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`아주 좋은 생각이야.`,JPN:`それはいい考えね。`,ENG:`That's a great idea.`,TWN:`好主意。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`INGRID_STREGA_HALLOWEEN_NULL`,text:{KOREA:`너어! 지금 두 번째 받는 거 다 기억해!`,JPN:`君！　これで二度目でしょ！　ちゃんと覚えてるんだからね！`,ENG:`Hey! I know this is your second time getting a cookie!`,TWN:`你！是第二次來領吧！我都有記住喔！`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`INGRID_STREGA_HALLOWEEN_NULL`,text:{KOREA:`하나씩 받는 거야! 또 받으러 오면 가만 안 둔다?`,JPN:`一つずつだよ！　また貰いに来たら承知しないよ？`,ENG:`It's one per person, okay! Don't come back for more!`,TWN:`每人只能領一塊！再來領我就要生氣囉！`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`운세 중에 액운이 나온 분들은 말씀해 주세요!`,JPN:`運勢で凶が出た人は言ってくださいね！`,ENG:`Let us know if you got misfortune as your result!`,TWN:`運勢出現凶的人請找我！`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`액운이랑 작은 선물이랑 바꿔 드립니다~`,JPN:`凶を小さなプレゼントに交換してあげますよ～`,ENG:`You can exchange it for a small gift!`,TWN:`我們會用小禮物換走厄運～`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CATHY_CIVIL_NULL_NULL`,text:{KOREA:`점장님이시죠? 기획하시느라 고생 깨나 하셨겠는데요?`,JPN:`店長さんですか？　企画でご苦労なさったでしょう？`,ENG:`You're the owner, right? You must've gone through a lot of trouble to make this happen.`,TWN:`你就是店長吧？策劃這場活動應該花不少力氣吧？`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CATHY_CIVIL_NULL_NULL`,text:{KOREA:`덕분에 좋은 기사가 나올 것 같아요. 좋은 공연, 감사합니다.`,JPN:`おかげでいい記事が書けそうです。いいイベントをありがとうございました。`,ENG:`It'll make a good article, though. Thank you for the great performance.`,TWN:`多虧你們，我應該能寫一篇不錯的報導，謝謝你們的精彩演出。`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`잘 봐 줬다니 고맙네.`,JPN:`楽しんでくれたようで、よかった。`,ENG:`I'm glad you enjoyed it.`,TWN:`也謝謝你來看我們的表演。`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`여기 특별한 마법을 걸어 만든 웨딩 디저트야. <color=#ffd34c>행복한 신부가 될 수 있는 마법</color>이 걸려 있어.`,JPN:`これは特別な魔法をかけて作ったウェディングデザートだ。<color=#ffd34c>幸せな花嫁になれる魔法</color>がかけてある。`,ENG:`Here. It's a wedding dessert with a special spell cast on it. The spell will help you become a <color=#ffd34c>happy bride</color>.`,TWN:`這是施加特別魔法的婚禮甜點，就是<color=#ffd34c>成為幸福新娘的魔法</color>。`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CATHY_CIVIL_NULL_NULL`,text:{KOREA:`와. 아껴 뒀다 먹어야겠네요. 아직은 상대가 없어서요.`,JPN:`わあ。大切に保管して食べないといけませんね。まだ相手がいなくて。`,ENG:`Ooh. I should save it for the future, then. I don't have anyone special yet.`,TWN:`哇，我現在又沒有對象，那要先收起來，等之後才能吃。`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CATHY_CIVIL_NULL_NULL`,text:{KOREA:`흐음…… 아닌가?`,JPN:`ふむ……いや、いるのかな？`,ENG:`Hmm... Or maybe I do.`,TWN:`嗯……或許有吧？`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`뭐, 그건 알아서 하고.`,JPN:`まあ、それは勝手にやってくれ。`,ENG:`Well, you do you.`,TWN:`喔喔，隨便你要什麼時候吃。`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`꼬마. 너도 포춘 쿠키 하나 받아 가.`,JPN:`ちびっ子。汝もフォーチュンクッキーを貰っていくといい。`,ENG:`Hey kid, take a fortune cookie.`,TWN:`小朋友，也送你一塊幸運餅乾。`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`LENI_NPC_SUPPLEMENT_GIRL`,text:{KOREA:`감사합니다, 공주… 아니, 마녀 신부님!`,JPN:`ありがとう、お姫……じゃなかった、魔女の花嫁さん！`,ENG:`Thank you, princ– I mean, witch bride!`,TWN:`謝謝公主……不對，是魔女新娘！`},stage:{bg:`WEDDING`,slots:{L:null,C:null,R:null}}}];export{e as default};